import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as s,W as a,E as i,P as n,N as o}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const x={id:"protocols",title:"Protocols and Interoperability",description:"Standards that let agents connect to anything — universal protocols, discovery, authentication, and loose coupling.",icon:"🔌",colorHex:"#0d9488",difficulty:"advanced",estimatedHours:10,prerequisites:["tools","teams-coordination"],chapters:[{id:"c1-interoperability",title:"The Interoperability Problem",description:"Why every system speaks a different language and the case for standards.",difficulty:"intermediate",estimatedMinutes:80,sections:[{id:"s1-tool-fragmentation",title:"Tool Fragmentation",description:"Why every system speaks a different language and the cost of incompatibility.",difficulty:"intermediate",readingMinutes:10},{id:"s2-universal-protocol",title:"The Case for a Universal Protocol",description:"Why one standard protocol unlocks exponential value for agent ecosystems.",difficulty:"intermediate",readingMinutes:12},{id:"s3-client-server",title:"Client-Server Architecture",description:"Providers and consumers — the fundamental relationship in tool protocols.",difficulty:"intermediate",readingMinutes:10},{id:"s4-runtime-discovery",title:"Discovery",description:"Finding what is available at runtime — dynamic capability advertisement.",difficulty:"intermediate",readingMinutes:10}]},{id:"c2-connecting",title:"Connecting to External Systems",description:"Consuming and exposing tools across system boundaries.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-consuming-tools",title:"Consuming External Tools",description:"Using tools provided by other systems through a standardized protocol.",difficulty:"advanced",readingMinutes:10},{id:"s2-exposing-capabilities",title:"Exposing Your Agent Capabilities",description:"Making your agent tools available to other systems and agents.",difficulty:"advanced",readingMinutes:12},{id:"s3-auth-across-boundaries",title:"Authentication Across Boundaries",description:"Identity, tokens, and trust — proving who you are across systems.",difficulty:"advanced",readingMinutes:10},{id:"s4-handling-large-responses",title:"Handling Large Responses",description:"What to do when external systems return too much data — summarization and collapse.",difficulty:"advanced",readingMinutes:10}]},{id:"c3-protocol-design",title:"Protocol Design Principles",description:"How to design protocols that evolve without breaking.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-loose-coupling",title:"Loose Coupling",description:"Changing one side without breaking the other — the key to maintainable integrations.",difficulty:"advanced",readingMinutes:10},{id:"s2-resource-discovery",title:"Resource Discovery",description:"Advertising capabilities dynamically — letting consumers find what they need.",difficulty:"advanced",readingMinutes:10},{id:"s3-permission-bridging",title:"Permission Bridging",description:"Propagating trust across system boundaries — who is allowed to do what where.",difficulty:"advanced",readingMinutes:12},{id:"s4-versioning",title:"Versioning and Compatibility",description:"Evolving protocols without breaking existing consumers.",difficulty:"advanced",readingMinutes:10}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Tool Fragmentation Problem"}),e.jsx("p",{children:"As agents multiply across organizations, each tends to arrive with its own set of tools, built in its own way, speaking its own interface language. The result is fragmentation: a landscape where every agent is an island, unable to share capabilities with any other. This is the starting problem that communication protocols are designed to solve."}),e.jsx(t,{title:"Tool Fragmentation",number:"9.1",children:e.jsx("p",{children:"Tool fragmentation occurs when every agent or system defines its own bespoke interface for the capabilities it exposes or consumes. Each integration requires custom code to bridge the differences. The cost grows quadratically: with N systems, you may need up to N² custom bridges, and every new system added means N new integration points."})}),e.jsx("p",{children:"Fragmentation is not just an engineering inconvenience. It creates operational brittleness: a change to one system's interface ripples outward, breaking every agent that depended on it. It also creates security risks — each bespoke integration tends to handle authentication and authorization slightly differently, and the gaps between them are where vulnerabilities hide."}),e.jsx(s,{title:"The Pre-USB World",children:e.jsx("p",{children:"Before USB, every peripheral device — keyboard, mouse, printer, camera — came with its own connector. Computers shipped with a dozen different ports, cables were not interchangeable, and adding a new device often required opening the machine. USB replaced all of that with a single standard. The same principle applies to agent-to-tool communication: a shared protocol eliminates the proliferation of bespoke connectors."})}),e.jsx(a,{title:"The Hidden Cost of Custom Integrations",children:e.jsx("p",{children:"Teams often underestimate the maintenance burden of custom integrations. Each one is a liability: it must be updated when either side changes, it often lacks error handling, and it typically has no shared test coverage. Over time, the sum of custom integrations can consume more engineering effort than the agents themselves."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-1-1",difficulty:"beginner",question:"An organization has 5 agents, each with 4 unique tools. If every agent needs a custom bridge to use every other agent's tools, how many bridges are required? What happens when a sixth agent is added?",hint:"Count unique ordered pairs. With N systems needing to talk to each other, the number of directed connections is N×(N-1).",solution:"With 5 agents, each needing to connect to 4 others, that is 5×4 = 20 directed bridges. Adding a sixth agent requires 5 new outgoing bridges (sixth to each existing) plus 5 incoming bridges (each existing to sixth) — 10 more, for a total of 30. A universal protocol collapses all of these to a single standard each system implements once."},{id:"ex9-1-2",difficulty:"intermediate",question:"Describe two concrete failure modes that arise specifically from fragmentation — problems that would not exist if all agents shared a single protocol.",hint:"Think about what happens when one side of a custom bridge changes, and how security decisions get made inconsistently.",solution:"First, version drift: when one system updates its interface, every custom bridge to it breaks simultaneously, with no standard mechanism to signal the change or negotiate compatibility. Second, inconsistent authorization: each custom integration implements permission checks differently, creating gaps where an agent can access something it should not because one bridge uses weaker checks than another. Both problems disappear when all parties implement a shared protocol that defines how versioning and authorization work."},{id:"ex9-1-3",difficulty:"advanced",question:"Some argue that standardized protocols sacrifice expressiveness for compatibility — a universal interface can only expose the lowest common denominator of what any tool can do. How would you design a protocol to avoid this tradeoff?",hint:"Consider how the web solved this: HTTP is universal, but it does not constrain what can be served over it. What is the equivalent for tool protocols?",solution:"The key is to separate the transport and discovery layer from the capability layer. A universal protocol should standardize how you find, call, and get results from tools — not what those tools do. Extensions and domain-specific metadata can ride on top of the core protocol. This is how HTTP works: the protocol is universal, but nothing prevents a server from exposing rich, domain-specific APIs over it. A well-designed agent protocol should similarly define a thin, stable core with extension points for richer semantics."}]})]})}const k=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Case for a Universal Protocol"}),e.jsx("p",{children:"The answer to fragmentation is standardization. When every participant in an ecosystem agrees to speak the same language — using the same message formats, discovery mechanisms, and capability descriptions — the number of custom integrations collapses to zero. Each participant implements the protocol once, and immediately gains access to every other participant that has done the same."}),e.jsx(t,{title:"Universal Tool Protocol",number:"9.2",children:e.jsx("p",{children:"A universal tool protocol is a shared specification that defines how an agent discovers what a tool does, how it calls that tool, and how it interprets the response. By implementing the protocol, a tool becomes accessible to any agent that also implements it — without any custom integration work. The protocol is the integration."})}),e.jsx("p",{children:"Protocols succeed when they make the right thing easy and the wrong thing hard. A good protocol for agent-tool communication must handle four concerns: capability description (what can this tool do?), invocation (how do I call it?), error reporting (what went wrong and why?), and authentication (am I allowed to use this?). Getting all four right is what separates a durable standard from one that eventually gets abandoned."}),e.jsx(n,{title:"Separate Discovery from Invocation",number:"9.1",children:e.jsx("p",{children:'A universal protocol should treat capability discovery and invocation as distinct concerns with separate mechanisms. Discovery answers "what can you do?" and should be safe to call without side effects. Invocation answers "do this now" and may have consequences. Conflating them — or skipping discovery entirely — leads to agents calling tools blindly and failing in unpredictable ways.'})}),e.jsx(o,{title:"Adoption requires network effects",type:"note",children:e.jsx("p",{children:"A protocol is only valuable if many participants adopt it. A technically superior protocol with few adopters is less useful than a good-enough protocol with broad support. This is why momentum and tooling ecosystem matter as much as technical design when evaluating whether to adopt a protocol."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-2-1",difficulty:"beginner",question:"A universal protocol must specify how tools describe their capabilities. What four pieces of information does a tool description need to provide for an agent to use it correctly?",hint:"Think about what a human would need to know to use a tool: what it does, what inputs to give it, what it returns, and when it might fail.",solution:"A tool description needs: (1) Name and purpose — a human-readable label and a clear description of what the tool accomplishes. (2) Input schema — the parameters it accepts, their types, and which are required. (3) Output schema — the shape and type of the response on success. (4) Error conditions — what errors can occur and under what circumstances, so the agent can handle them gracefully rather than treating all failures as identical."},{id:"ex9-2-2",difficulty:"intermediate",question:"Why is it important that a protocol's discovery endpoint have no side effects? What could go wrong if listing available tools caused them to execute or changed their state?",hint:"Think about how an agent might call discovery repeatedly during planning — and what happens if that has consequences.",solution:"Agents often explore available tools during planning phases, potentially calling discovery many times. If discovery had side effects — incrementing a counter, reserving resources, triggering notifications — repeated exploration would cause unintended actions. It would also make recovery difficult: if an agent crashes mid-plan and restarts, it would re-trigger those side effects on restart. Safe discovery lets agents be exploratory and resilient without unintended consequences."},{id:"ex9-2-3",difficulty:"advanced",question:"Compare two protocol design strategies: (A) a single tightly-specified protocol covering all cases, and (B) a minimal core protocol with extension points. For agent-tool communication specifically, which would you recommend and why?",hint:"Consider how tool capabilities vary: some tools are simple functions, others are stateful services with complex flows. Can one tight spec cover all cases?",solution:"Strategy B is generally better for agent-tool communication. Tool capabilities vary enormously: a calculator tool is a simple stateless function, while a database tool may involve sessions, transactions, and complex query languages. A single tight spec either becomes so complex it is hard to implement correctly, or so simple it cannot express rich capabilities. A minimal core (invocation, discovery, error reporting) with extension points for domain-specific metadata gives implementors the flexibility to express their tools fully while ensuring basic interoperability. This mirrors how successful protocols like HTTP have evolved."}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Client–Server Roles in Agent Protocols"}),e.jsx("p",{children:"When agents communicate with tools through a shared protocol, each participant plays a role. The same agent may act as a client in one interaction and a server in another. Understanding these roles — and the obligations that come with each — is essential to designing systems that compose cleanly."}),e.jsx(t,{title:"Protocol Client and Server",number:"9.3",children:e.jsxs("p",{children:["In an agent communication protocol, the ",e.jsx("strong",{children:"client"})," is the party that initiates requests — typically an agent seeking to invoke a capability. The",e.jsx("strong",{children:" server"})," is the party that hosts capabilities and responds to requests — typically a tool provider or another agent. A single system can be both: an agent that calls external tools is a client to those tools, while simultaneously acting as a server to a higher-level agent that calls it."]})}),e.jsx("p",{children:"The client–server distinction matters because each role carries different responsibilities. A server must faithfully describe its capabilities, validate incoming requests, and return consistent responses. A client must respect the server's schema, handle errors gracefully, and not assume more capability than the server advertises. When these responsibilities are violated — a server that returns undocumented fields, a client that ignores error codes — integrations become fragile."}),e.jsx(s,{title:"A Restaurant Menu",children:e.jsx("p",{children:"A restaurant is a server: it publishes a menu (capability description), accepts orders (invocations), and returns dishes (responses). Diners are clients: they choose from the menu, submit orders in the expected format, and receive what was described. A diner who orders something not on the menu, or a kitchen that delivers something different from what was ordered, breaks the protocol. Both roles have obligations."})}),e.jsx(n,{title:"Roles Are Contextual, Not Fixed",number:"9.2",children:e.jsx("p",{children:"Design agent systems so that any component can occupy either the client or server role depending on the interaction. An agent that can only be a client cannot be composed into larger systems where other agents need to invoke its capabilities. Symmetry in role capability is a sign of a well-designed protocol participant."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-3-1",difficulty:"beginner",question:"In a system where a research agent calls a web search tool, which party is the client and which is the server? If that same research agent is called by an orchestrator agent, what roles does the research agent now occupy?",hint:"Role is determined by who initiates the request, not by what the system does in general.",solution:"When the research agent calls the web search tool, the research agent is the client and the web search tool is the server. When the orchestrator calls the research agent, the research agent becomes the server — it must expose its capabilities, accept invocations, and return responses. The research agent simultaneously occupies both roles: server to the orchestrator and client to the web search tool. This stacking is normal and expected in multi-agent systems."},{id:"ex9-3-2",difficulty:"intermediate",question:"A server returns a response with a field that is not described in its capability schema. A client receives this and tries to use the undocumented field. What problems can arise, and who is responsible?",hint:"Consider what happens when the server later removes or renames that field — and whether the client had any basis for relying on it.",solution:"The server violated the protocol by returning undocumented data, and the client compounded the problem by relying on it. The immediate risk is instability: the client now has a hidden dependency on behavior that was never promised, which may change or disappear without notice. The deeper problem is that capability schemas serve as contracts — once clients start working around them, the contract becomes meaningless and the integration is essentially custom again, defeating the purpose of the protocol. Responsibility is shared: servers should not emit undocumented fields, and clients should ignore or flag them rather than silently depending on them."},{id:"ex9-3-3",difficulty:"advanced",question:"Design the minimal set of obligations for a protocol server. What must a well-behaved server guarantee, and what is explicitly outside its responsibility?",hint:"Think about the contract a server owes its clients versus what the client is responsible for providing.",solution:"A well-behaved server must: (1) Accurately describe its capabilities — the schema is a promise, not a suggestion. (2) Validate inputs before processing — the server should not crash or produce nonsense when given malformed requests. (3) Return responses that match its advertised output schema. (4) Use error codes consistently — the same class of problem should produce the same error type. Outside its responsibility: the server cannot control how the client interprets results or whether the client handles errors gracefully. It also should not be responsible for the client's authentication credentials or for ensuring the client is calling tools in a sensible order. Those are client-side concerns."}]})]})}const T=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Runtime Discovery"}),e.jsx("p",{children:"A static list of tools baked into an agent at build time creates a rigid system: adding a new capability requires redeploying the agent. Runtime discovery solves this by letting agents ask, at the moment they need it, what tools are available and what those tools can do. The agent's capability set becomes dynamic rather than fixed."}),e.jsx(t,{title:"Runtime Discovery",number:"9.4",children:e.jsx("p",{children:"Runtime discovery is the ability of an agent to query a tool server at execution time to learn what capabilities are available, what inputs they require, and what outputs they produce — without this information being hard-coded ahead of time. The agent adapts its behavior to the actual tools present, rather than assuming a fixed inventory."})}),e.jsx("p",{children:"Runtime discovery enables a new class of agent behavior: adaptive tool use. An agent equipped with discovery can reason about which available tools are suited to the current task, combine them in ways not anticipated at design time, and gracefully degrade when expected tools are absent. This composability is what makes protocol-based systems fundamentally more flexible than hard-wired integrations."}),e.jsx(o,{title:"Discovery can be expensive",type:"tip",children:e.jsx("p",{children:'Querying a server to list all available tools is a network call that takes time. Agents that call discovery before every single action introduce latency. A practical pattern is to cache the capability list at the start of a task and refresh only when a call fails with an "unknown tool" error — balancing freshness with performance.'})}),e.jsx(a,{title:"Discovery is not authorization",children:e.jsx("p",{children:"The fact that a tool appears in a discovery response does not mean the calling agent is authorized to use it. Discovery tells you what exists; authorization tells you what you are permitted to call. Agents must not treat a tool's presence in a discovery list as implicit permission to invoke it without checking access controls."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-4-1",difficulty:"beginner",question:"What is the difference between static tool configuration and runtime discovery? Give one advantage and one disadvantage of each approach.",hint:"Think about flexibility, predictability, and what happens when the set of available tools changes.",solution:"Static configuration: the agent's available tools are defined at build or deploy time. Advantage: predictable — you always know exactly what the agent can do. Disadvantage: inflexible — adding or removing a tool requires redeploying the agent. Runtime discovery: the agent queries for available tools when it runs. Advantage: flexible — tools can be added or removed without touching the agent. Disadvantage: introduces network calls, potential latency, and the possibility that expected tools are not available at runtime."},{id:"ex9-4-2",difficulty:"intermediate",question:"An agent discovers 40 available tools at runtime. How should it decide which tools to include in its reasoning context, given that including all 40 tool descriptions may be impractical?",hint:"Consider relevance to the current task, the cost of including irrelevant tools, and strategies for narrowing the set.",solution:"The agent should filter tools based on task relevance before including them in its reasoning context. Strategies include: using tool categories or tags to narrow by domain (only include database tools when the task involves data retrieval), semantic matching between the task description and tool descriptions, or a two-stage process where a lightweight filter selects candidate tools before full reasoning. Including all 40 tools wastes context and may confuse the agent by introducing options irrelevant to the task. The goal is a focused, relevant tool set, not an exhaustive one."},{id:"ex9-4-3",difficulty:"advanced",question:"Design a caching strategy for tool discovery that balances freshness with performance. Under what conditions should the cache be invalidated, and how should an agent handle a call that fails because a cached tool no longer exists?",hint:'Consider time-based expiry, error-triggered refresh, and the difference between "tool not found" and other error types.',solution:'A robust caching strategy: (1) Cache the tool list at the start of each task execution with a short TTL (e.g., 5 minutes). (2) On a "tool not found" error, immediately invalidate and refresh the cache before retrying. (3) On any other error type, do not refresh — the issue is likely not a stale cache. (4) For long-running tasks, periodically refresh in the background to catch tool additions. When a call fails because a cached tool no longer exists, the agent should refresh discovery, check if a replacement tool exists that covers the same capability, and either retry with the replacement or surface a graceful error to the caller explaining which capability became unavailable.'}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Consuming Tools as a Client"}),e.jsx("p",{children:"When an agent acts as a protocol client, it takes on the responsibility of using tools correctly. This is not just about calling the right function with the right arguments. It involves discovering capabilities, validating that a tool fits the task, handling the full range of responses — including errors — and doing all of this in a way that the system can recover from when things go wrong."}),e.jsx(t,{title:"Tool Consumption Lifecycle",number:"9.5",children:e.jsxs("p",{children:["Consuming a tool through a protocol involves four stages: ",e.jsx("strong",{children:"discovery"}),"(learning that the tool exists and what it can do), ",e.jsx("strong",{children:"selection"}),"(deciding this tool fits the current need), ",e.jsx("strong",{children:"invocation"})," (calling the tool with correctly formed inputs), and ",e.jsx("strong",{children:"result handling"})," (interpreting the response, whether success or error, and deciding what to do next)."]})}),e.jsx("p",{children:"Agents that skip the selection stage — calling tools because they exist rather than because they fit — produce noisy, unreliable behavior. Good tool selection requires matching the task to the tool's declared purpose, checking that required inputs are available, and considering whether the tool's output format is compatible with what the next step in the plan expects."}),e.jsx(n,{title:"Validate Before You Invoke",number:"9.3",children:e.jsx("p",{children:"Before calling a tool, verify that you can satisfy its required inputs and that its output will serve the next step. Calling a tool and then discovering mid-task that the output format is wrong wastes execution and can leave the system in a partial state. Input validation is cheap; partial execution is expensive."})}),e.jsx(o,{title:"Idempotency matters at the client",type:"tip",children:e.jsx("p",{children:"When retrying a failed tool call, prefer tools that are idempotent — calling them twice produces the same result as calling them once. Before retrying any call, check whether the tool declares itself idempotent. Non-idempotent retries (sending an email twice, charging a card twice) cause real harm."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-5-1",difficulty:"beginner",question:"An agent needs to retrieve customer data. It discovers two tools: one that fetches a customer by ID and one that searches customers by name. The task provides only a customer name. Which tool should the agent select and why?",hint:"Consider what inputs you have versus what each tool requires.",solution:"The agent should select the search-by-name tool. The agent has a name but not an ID, so the fetch-by-ID tool cannot be used without first obtaining the ID — which would require an additional step. Using the available input (name) to call the matching tool is the direct path. Choosing the ID-based tool would require the agent to find the ID first, adding unnecessary steps and potential failure points."},{id:"ex9-5-2",difficulty:"intermediate",question:"A tool call fails with a timeout error. The tool updates records in a database. Should the agent retry immediately? What information would help it decide?",hint:"A timeout means you do not know whether the operation completed. Consider the difference between a read operation timing out versus a write operation timing out.",solution:"The agent should not retry immediately without knowing whether the operation completed. A timeout on a write operation means the record may or may not have been updated — a blind retry could create a duplicate update. Helpful information: does the tool declare itself idempotent? If yes, retrying is safe. If not, the agent should first query the current state of the record to determine whether the update happened before deciding to retry. If no idempotency information is available, the safest path is to surface the ambiguity to a human or a higher-level supervisor rather than guessing."},{id:"ex9-5-3",difficulty:"advanced",question:"Design a tool invocation strategy for an agent that must call three tools in sequence, where each tool's output feeds into the next. How should the agent handle a failure in the second tool when the first tool has already completed and had side effects?",hint:"Think about compensation actions, rollback, and the information the agent needs to undo completed steps.",solution:'The agent needs a compensation strategy for the first tool before invoking the second. Before calling any tool with side effects in a chain, check whether the tool provides a rollback or compensation action (e.g., a "delete record" tool paired with a "create record" tool). If compensation is available, the agent should record the completion of step one along with the compensation action needed to undo it. On failure in step two, it executes the compensation action for step one before surfacing the error. If no compensation is available, the agent must surface the partial completion explicitly — describing what happened and what did not — so that a human or recovery process can decide how to proceed. Silent partial completion is the most dangerous outcome.'}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Exposing Capabilities as a Server"}),e.jsx("p",{children:"When an agent or service acts as a protocol server, it publishes capabilities that other agents can discover and invoke. The quality of that publication — how accurately it describes inputs, outputs, and behavior — determines whether clients can use those capabilities effectively or will constantly encounter surprises."}),e.jsx(t,{title:"Capability Exposition",number:"9.6",children:e.jsx("p",{children:"Exposing a capability through a protocol means providing a machine-readable description of what the capability does, what it accepts as input, what it returns, what errors it can produce, and any constraints on how it should be called. The description is a contract: clients are entitled to rely on it, and servers are obligated to honor it."})}),e.jsx("p",{children:"The most common failure in capability exposition is over-simplification: describing a tool as doing one thing when it actually does several subtly different things depending on which inputs are provided. This forces clients to discover the nuance through trial and error rather than through documentation. The discipline of writing capability descriptions is partly the discipline of forcing yourself to be honest about what your tool actually does."}),e.jsx(s,{title:"A Job Posting",children:e.jsx("p",{children:"When a company publishes a job posting, they describe required skills, responsibilities, and working conditions. A vague or inaccurate posting wastes everyone's time — candidates apply for jobs they are not suited for, and the company interviews people who cannot do the work. A precise posting attracts the right candidates and sets correct expectations. Tool capability descriptions work the same way: precision serves everyone."})}),e.jsx(a,{title:"Side Effects Must Be Declared",children:e.jsx("p",{children:"Any capability that modifies state, sends messages, charges money, or has any effect beyond returning data must declare those side effects explicitly. Clients have no way to infer that calling a tool will trigger an external action unless the description says so. Undeclared side effects are one of the most common sources of agent errors."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-6-1",difficulty:"beginner",question:"A tool sends a notification to a user's email. What information must its capability description include that a purely read-only tool would not need?",hint:"Think about what a client needs to know before calling a tool that will reach out to another person.",solution:"The description must declare: (1) That the tool sends an email — the external side effect. (2) Who receives the email — is it a fixed address, or does the caller specify? (3) Whether the send can be undone — it cannot, so the tool is non-reversible. (4) Any rate limits or deduplication behavior — calling it twice may send two emails. (5) Whether sending can fail silently (e.g., if the address is invalid). A read-only tool need only describe its inputs and outputs; a side-effecting tool must also describe its reach and consequences."},{id:"ex9-6-2",difficulty:"intermediate",question:"A developer exposes a search tool that returns different result counts based on undocumented business logic (e.g., premium users get more results). How does this inconsistency affect clients, and how should it be handled in the capability description?",hint:"Consider how the client would plan its next action based on the expected response shape.",solution:`Clients that receive different result counts than expected may either under-paginate (thinking they have seen all results when they have not) or over-paginate (requesting more pages that do not exist). The inconsistency breaks the client's ability to plan correctly. The capability description should explicitly document the result-count variability — ideally by exposing a "max results" field in the response, or by describing the factors that affect it. If the business logic cannot be documented, the tool should be split into variants that behave consistently, or the variable behavior should be surfaced through response metadata rather than hidden.`},{id:"ex9-6-3",difficulty:"advanced",question:"You are designing a server that exposes three related capabilities: create, update, and delete for a resource type. What shared schema elements should appear in all three descriptions, and what is unique to each? How would you structure the capability descriptions to minimize redundancy while keeping them self-contained?",hint:"Think about common input fields (like resource ID), common error conditions, and the different side effect profiles of each operation.",solution:"Shared elements: resource identifier (required for update and delete, returned by create), authentication context, and common error types (unauthorized, not found, service unavailable). Unique to create: the full input schema for the new resource, the returned ID, and the fact that the resource did not previously exist. Unique to update: which fields are mutable versus immutable, partial vs. full update semantics. Unique to delete: whether deletion is soft or hard, whether it cascades, and whether it is reversible. Structuring: define a shared base schema for common fields and error types, then compose it into each operation description. Self-containment matters more than avoiding repetition — clients should be able to read one description without needing to cross-reference others."}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Authentication Across Protocol Boundaries"}),e.jsx("p",{children:"When an agent calls a tool hosted on a different server — possibly owned by a different organization — the question of identity becomes complex. Who is making the call: the agent, the user whose task triggered the agent, or the operator who deployed the agent? Authentication across protocol boundaries requires explicit decisions about which identity to present and how credentials flow through multi-hop chains."}),e.jsx(t,{title:"Identity Propagation",number:"9.7",children:e.jsx("p",{children:"Identity propagation is the question of whose credentials are presented when an agent calls a tool on behalf of someone else. The agent may carry its own service identity, the user's delegated credentials, or a scoped token that represents only the permissions needed for this specific task. Each choice carries different trust implications for the receiving server."})}),e.jsxs("p",{children:["In practice, three patterns are common. In the ",e.jsx("strong",{children:"agent identity"})," pattern, the agent presents its own credentials and the tool trusts the agent to act on behalf of any user. This is simple but grants the agent broad power. In the ",e.jsx("strong",{children:"delegated identity"})," pattern, the user's token is passed along, and the tool enforces the user's own permission set. This is more restrictive but requires the user to pre-authorize the flow. In the ",e.jsx("strong",{children:"scoped token"})," pattern, a purpose-specific token is generated that encodes exactly what the agent is allowed to do — nothing more."]}),e.jsx(n,{title:"Prefer Scoped Tokens for Cross-Boundary Calls",number:"9.4",children:e.jsx("p",{children:"When an agent must cross an organizational or service boundary to invoke a tool, use a scoped token that encodes only the specific permissions needed for the current task. Scoped tokens limit blast radius: if the token is intercepted or misused, the attacker gains only what the token permitted — not everything the agent or user can do."})}),e.jsx(a,{title:"Credential Leakage in Multi-Hop Chains",children:e.jsx("p",{children:"In a chain where Agent A calls Agent B which calls Tool C, the credentials passed at each hop may contain more permission than the next hop needs. Each link in the chain should receive only the credentials required to complete its step — not the full credentials of the originating user or agent. Passing full credentials through intermediate hops is one of the most common privilege escalation patterns."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-7-1",difficulty:"beginner",question:"A user asks an agent to read their calendar and draft a meeting invitation. The agent must call a calendar API. Should the agent use its own service credentials or the user's delegated token? What are the tradeoffs?",hint:"Think about what each credential set authorizes and what happens if the agent's credentials are used for all users.",solution:"The agent should use the user's delegated token. If it uses its own service credentials, it may access other users' calendars or be granted read/write to all accounts — violating the principle of least privilege. The user's delegated token limits access to what that user can see. The tradeoff is that delegated authentication requires the user to grant access upfront (an OAuth flow or similar), while service credentials are simpler to manage. The security benefit of delegated credentials strongly outweighs the setup cost for operations that touch personal data."},{id:"ex9-7-2",difficulty:"intermediate",question:"An agent is given a broad OAuth token by the user with read/write access to their entire file system. The agent's current task only requires reading one specific directory. How should the agent handle this mismatch between the token's scope and the task's actual needs?",hint:"Consider whether the agent should use the full token, or whether there is a better option.",solution:"The agent should not use the broad token directly if a more scoped alternative is available. If the protocol supports token downscoping — requesting a new token with reduced permissions — the agent should request a read-only token scoped to the specific directory before making the call. If downscoping is not available, the agent should document its use of the broad token in its reasoning trace and proceed with caution, avoiding any writes. The broader principle is that the agent is responsible for limiting its own privilege even when the user has granted more than necessary."},{id:"ex9-7-3",difficulty:"advanced",question:"Design an authentication scheme for a three-hop agent chain: a user triggers Agent A, which calls Agent B, which calls an external API. Each hop crosses an organizational boundary. What credentials should flow at each hop, and what should each participant verify?",hint:"Work outward from the principle of least privilege. Each hop should get only what it needs, and each participant should verify both identity and scope.",solution:"Hop 1 (User → Agent A): User authenticates to Agent A with their full user token. Agent A verifies the user's identity and checks that the requested task is within scope. Hop 2 (Agent A → Agent B): Agent A generates a scoped task token — it identifies Agent A as the caller, attests that it is acting on behalf of the user (by reference, not by forwarding the full user token), and encodes only the permissions Agent B needs to complete its part. Agent B verifies the token was issued by a trusted source (Agent A) and that the scope covers the operation. Hop 3 (Agent B → External API): Agent B generates another scoped token, narrowed further to only the external API call needed. The external API verifies the token's signature, the issuer's trust chain, and the scope. No hop receives the credentials from the previous hop verbatim — each generates a fresh, scoped token. This creates an auditable chain where each participant can be identified."}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Handling Large Tool Responses"}),e.jsx("p",{children:"Many real-world tools return far more data than an agent can use in a single reasoning step. A database query might return thousands of rows; a web scrape might return an entire page of HTML; a document retrieval might return a lengthy file. How an agent handles responses that exceed its practical processing capacity is a critical design concern."}),e.jsx(t,{title:"Response Overflow",number:"9.8",children:e.jsx("p",{children:"Response overflow occurs when a tool returns more data than the agent can effectively include in its context window or process in a single step. Without a strategy for handling overflow, agents either truncate data silently (losing potentially important information) or become unable to continue until the response is managed down to a usable size."})}),e.jsxs("p",{children:["Three strategies address overflow. ",e.jsx("strong",{children:"Pagination"})," lets the agent request results in chunks, processing each chunk before requesting the next. ",e.jsx("strong",{children:"Projection"}),"narrows the request itself — asking the tool for only the fields or records that are needed rather than accepting everything and discarding most of it. ",e.jsx("strong",{children:"Summarization"}),"uses a separate step to condense a large response into the salient facts before passing them forward. Each strategy has different tradeoffs in latency, precision, and complexity."]}),e.jsx(s,{title:"Drinking from a Firehose",children:e.jsx("p",{children:"Imagine being handed a firehose and told to drink from it. You could try to take in everything and spill most of it, or you could turn down the pressure (project your request), drink in sips (paginate), or have someone filter it into a glass for you (summarize). Each method works, but the right choice depends on how thirsty you are, how long you have, and whether the flavor of each sip matters."})}),e.jsx(o,{title:"Ask the tool to do the filtering",type:"tip",children:e.jsx("p",{children:"Whenever possible, push filtering and projection into the tool call itself rather than handling it client-side. A tool that returns only the 5 most relevant results is almost always better than one that returns 500 results that the agent then has to sort through. Well-designed tools accept query parameters that narrow their output to what is actually needed."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-8-1",difficulty:"beginner",question:"A tool returns a list of 10,000 customer records. The agent needs to find the 5 most recently created. What is the most efficient strategy, and why is loading all 10,000 records into context a bad approach?",hint:"Think about what work can be done at the tool level versus what must be done by the agent.",solution:"The most efficient strategy is projection at the tool level: request only the 5 most recently created records, sorted by creation date, directly in the query. Loading all 10,000 records is wasteful because it consumes context space, adds latency, and requires the agent to sort through irrelevant data. The agent is not a good place to do database-style operations — the tool is. Always prefer pushing filters into the tool call over processing large results client-side."},{id:"ex9-8-2",difficulty:"intermediate",question:"An agent needs to process all records in a result set of unknown total size. Design a pagination strategy that handles the case where new records are added to the set while the agent is paginating through it.",hint:"Consider cursor-based pagination versus offset-based pagination. Which is stable when the underlying data changes?",solution:"Use cursor-based pagination rather than offset-based. Offset pagination (page 1 = records 0-99, page 2 = records 100-199) breaks when new records are inserted at the beginning — the offset shifts and the agent may see duplicate or skipped records. Cursor-based pagination uses a stable identifier (e.g., the ID of the last seen record) as the starting point for each subsequent request. New records inserted before the cursor position do not affect subsequent pages. The agent should also record which cursors it has processed so that if it is interrupted and restarted, it can resume from the last checkpoint rather than starting over."},{id:"ex9-8-3",difficulty:"advanced",question:"A tool returns a 50,000-word document as a single response. The agent needs to answer a specific question about a topic mentioned somewhere in the document. Compare the tradeoffs of three approaches: (1) summarize the whole document first, (2) paginate through it looking for the relevant section, (3) use a separate embedding search to locate the relevant passage.",hint:"Consider latency, information loss, and the precision of each approach for the specific use case.",solution:"(1) Whole-document summarization: fast to implement, but summarization may discard the specific detail the agent needs, especially if the topic is minor. High information loss risk. (2) Paginated reading: complete but slow — the agent reads every page even if the answer is near the end. Guarantees no information loss but wastes significant processing time. (3) Embedding search: fastest and most precise for targeted questions — it jumps directly to the relevant passage. Requires a pre-built or on-the-fly embedding index, adding infrastructure complexity. Recommendation: for targeted factual questions about long documents, embedding search is strongly preferable. For questions that require synthesizing the whole document, summarization (with careful prompt design to preserve specifics) may be necessary. Pagination is rarely the right choice for length documents unless the agent must process every section."}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Loose Coupling in Protocol Design"}),e.jsx("p",{children:"The goal of a protocol is to let participants work together without depending intimately on each other's internals. This property — loose coupling — is what gives protocol-based systems their durability. When participants are loosely coupled, either side can evolve independently as long as the contract between them is honored."}),e.jsx(t,{title:"Loose Coupling",number:"9.9",children:e.jsx("p",{children:"Loose coupling in a protocol means that each participant depends on the other only through the protocol interface — not through knowledge of each other's implementation, internal state, or deployment details. A client should be able to swap the tool it calls for any other that implements the same interface, and a server should be able to change its implementation without clients needing to update."})}),e.jsx("p",{children:"Tight coupling creeps in through seemingly innocent shortcuts: an agent that parses a tool's internal error message strings to decide what to do next, a tool that returns fields the client did not ask for and that the client now depends on, a client that knows the tool's database schema and queries it directly. Each of these creates a hidden dependency that does not appear in the protocol contract but will break when either side changes."}),e.jsx(s,{title:"Power Outlets",children:e.jsx("p",{children:"A power outlet and a plug are loosely coupled: the outlet does not know or care what device is plugged into it, and the device does not know or care how the electricity is generated. The standard defines the interface (voltage, frequency, socket shape), and anything that matches the interface works. Devices and grids can be upgraded independently. Tight coupling would be like a lamp that can only work with one specific power plant."})}),e.jsx(n,{title:"Depend on the Interface, Not the Implementation",number:"9.5",children:e.jsx("p",{children:"Any behavior that is not documented in the protocol contract should not be relied upon. If a tool happens to return results in alphabetical order but does not document that ordering, clients must not depend on it. Documenting behavior is a commitment; undocumented behavior is noise. Build only on commitments."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-9-1",difficulty:"beginner",question:'An agent parses the text of error messages returned by a tool to extract the error code ("Error 404: Not found"). Why is this tightly coupled, and what would a loosely coupled alternative look like?',hint:"Think about what happens when the error message text changes but the underlying error condition remains the same.",solution:'Parsing error message text is tight coupling because the agent now depends on the specific wording of the message — implementation detail that the tool author may change at any time without considering it a breaking change. A loosely coupled alternative uses a structured error response: a machine-readable error code (e.g., "NOT_FOUND") in a dedicated field, separate from the human-readable message. The agent reads the code field; the message can change freely without breaking anything.'},{id:"ex9-9-2",difficulty:"intermediate",question:'A tool returns a "metadata" field containing internal system information (server name, build version, processing time). Some clients start logging this data. Why is this a coupling problem, and how should it be handled?',hint:"Consider who owns the metadata field and what happens when the tool removes or restructures it.",solution:'The tool never contracted to provide this metadata, so clients have no right to depend on it. When the tool removes or restructures the field — as it eventually will — those clients break unexpectedly. The problem has two sides: the tool should not be returning undocumented fields, and clients should ignore fields they did not explicitly request and that are not in the documented schema. If clients genuinely need processing time metrics, the right solution is for the tool to add a documented "response_metadata" field with a stable schema that is explicitly part of the contract.'},{id:"ex9-9-3",difficulty:"advanced",question:"A team is designing a new tool protocol and debating two options: (A) a schema that exactly matches the current tool implementations, or (B) an abstract schema designed around client needs, which tools then implement. Which approach leads to better coupling, and why?",hint:"Think about whose perspective should drive the interface: the implementer or the user?",solution:"Option B leads to better coupling. When the schema mirrors current tool implementations, clients are de facto coupled to those implementations — the schema leaks internal concerns like field names chosen for database convenience or response shapes chosen for server efficiency. When the schema is designed around client needs, tools adapt their responses to match the contract, keeping their internal details private. This is the foundational principle of interface segregation: the interface should be defined by the consumer, not the provider. It forces tool authors to think about what clients actually need rather than what is easiest to expose."}]})]})}const B=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Resource Discovery and Navigation"}),e.jsx("p",{children:"Tool discovery tells an agent what capabilities exist. Resource discovery takes this further: it lets an agent explore the data and objects that tools operate on, not just the tools themselves. When an agent can discover and navigate resources as well as capabilities, it gains the ability to work with large, dynamic datasets without needing hard-coded knowledge of their structure."}),e.jsx(t,{title:"Resource Discovery",number:"9.10",children:e.jsx("p",{children:"Resource discovery is the ability to enumerate the specific data objects, documents, or entities that a tool can act on — and to navigate their relationships. Rather than hard-coding resource identifiers, an agent uses discovery to find what is available, select relevant items, and follow links between related resources to build context before taking action."})}),e.jsx("p",{children:"A protocol that supports resource discovery lets agents behave more like explorers than executors. An executor knows exactly what it wants and calls for it directly. An explorer can navigate an unfamiliar environment — following links, reading descriptions, narrowing scope — until it finds the right resource to act on. This is especially valuable in enterprise contexts where data structures are complex and not fully known at design time."}),e.jsx(n,{title:"Resources Should Be Self-Describing",number:"9.6",children:e.jsx("p",{children:"Each resource returned through a protocol should include enough information for an agent to decide whether it is relevant and what actions can be taken on it — without requiring a separate request. A resource that provides only an identifier forces the agent to make a follow-up call for every resource it encounters. Self-describing resources make exploration efficient."})}),e.jsx(o,{title:"Discovery depth should be bounded",type:"note",children:e.jsx("p",{children:"Resource graphs can be arbitrarily deep — a document links to folders, which link to projects, which link to teams, which link to organizations. Agents exploring resource graphs without depth limits can spend enormous time navigating before doing any useful work. Well-designed protocols provide filters, relevance signals, or explicit depth hints to keep discovery focused."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-10-1",difficulty:"beginner",question:"An agent is tasked with updating a specific document but only has the document's title, not its ID. The protocol supports resource discovery. Describe the steps the agent should take to find and then update the correct document.",hint:"Think about the sequence: discover, filter, confirm, act.",solution:"Step 1: Call the resource discovery endpoint with the document title as a search filter. Step 2: Review the returned resources — if multiple documents share the title, the agent needs additional signals (author, date, content snippet) to select the right one. Step 3: Confirm the selected resource by examining its description or a preview before taking any action. Step 4: Use the discovered resource's identifier to call the update tool. The key is not to conflate discovery and action — always confirm you have the right resource before modifying it."},{id:"ex9-10-2",difficulty:"intermediate",question:"A protocol allows an agent to navigate from a project resource to its child tasks, from tasks to their assignees, and from assignees to their other tasks. An agent needs to find all tasks assigned to people working on a specific project. What is the most efficient navigation path, and what is the risk of a naive traversal?",hint:"Think about fan-out: how many requests does each navigation step require, and how quickly can the number grow?",solution:"Most efficient path: fetch the project, get its task list (one call), extract unique assignees from the task list (no additional calls if tasks include assignee info), then for each unique assignee fetch their full task list. The risk of naive traversal: starting from assignees and navigating to all their projects first would fetch all projects for all assignees — including projects unrelated to the one we care about. That creates enormous fan-out. The efficient path always starts from the constrained resource (the specific project) and expands outward only as far as needed, avoiding the explosion of visiting unconstrained resources first."},{id:"ex9-10-3",difficulty:"advanced",question:"Design a resource discovery response format that lets an agent determine, from a single response, whether a resource is relevant to its task, what actions it can take on the resource, and where to find related resources — without requiring additional calls.",hint:"Think about the three categories of metadata an agent needs: relevance signals, capability links, and relationship links.",solution:"The response should include: (1) Identity: a stable ID, human-readable name, and resource type. (2) Relevance signals: a description, key attributes (dates, tags, status), and a relevance score if the request included a search query. (3) Available actions: a list of protocol-standard actions the caller is permitted to take on this resource (read, update, delete, comment), reflecting the caller's current permissions — not all possible actions. (4) Relationship links: named links to related resources (parent, children, related items), including the resource type at the other end so the agent can decide whether to follow them without making the request. The actions and relationships should use stable protocol identifiers, not implementation-specific field names, maintaining loose coupling."}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Permission Bridging Across Systems"}),e.jsx("p",{children:"When an agent operates across multiple systems — each with its own permission model — the question of how permissions translate between them becomes critical. An action that is permitted in system A may be explicitly forbidden in system B, or it may have no direct equivalent. Permission bridging is the design challenge of navigating these differences without accidentally granting more access than intended."}),e.jsx(t,{title:"Permission Bridging",number:"9.11",children:e.jsx("p",{children:"Permission bridging is the process of translating or mapping permissions from one system's model to another's when an agent acts across a protocol boundary. The bridge must decide what permissions from system A correspond to in system B — and must default to the more restrictive interpretation when an exact mapping does not exist."})}),e.jsx("p",{children:"Permission mismatches arise in several ways. System A may have fine-grained roles (read-only, comment-only, editor) while system B has only a binary authorized/unauthorized distinction. System A may grant access to a category (all documents in a project) while system B requires specific resource identifiers. System A may allow an action for a limited time while system B has no concept of time-bound permissions. Each mismatch is an opportunity for accidental privilege escalation."}),e.jsx(a,{title:"Assume Restriction When Mapping Is Ambiguous",children:e.jsx("p",{children:'When a permission in one system does not map cleanly to a permission in another, always assume the more restrictive interpretation. An agent that grants itself "editor" access in system B because its system A role was "commenter" is escalating privileges. When in doubt, treat the permission as not granted and surface the ambiguity for resolution rather than assuming the more permissive option.'})}),e.jsx(n,{title:"Bridges Should Be Explicit, Not Inferred",number:"9.7",children:e.jsx("p",{children:'Permission bridges should be explicitly defined mappings maintained by a human with authority over both systems — not inferred by the agent at runtime based on name similarity or guesswork. The agent is not the right party to decide what "editor in system A" means in system B. That is an organizational decision that must be made deliberately.'})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-11-1",difficulty:"beginner",question:'System A has three permission levels: "viewer", "editor", and "admin". System B has two: "read" and "write". How should each system A role map to system B, and what information is lost in the translation?',hint:`Consider what system B's "write" permission encompasses compared to system A's fine-grained distinction between editing and administering.`,solution:`Viewer → read (straightforward). Editor → write (reasonable, though system B's write likely covers actions system A reserves for admins). Admin → write (same mapping, with information loss: system B has no way to distinguish an editor from an admin). The key loss is granularity: system B cannot represent the difference between editing and administrative actions. If the bridge allows admins to be treated as just "write" users in system B, that is acceptable. The dangerous direction is the reverse: allowing a system B "write" user to be treated as an admin in system A, which would be a privilege escalation.`},{id:"ex9-11-2",difficulty:"intermediate",question:"A user's permission in system A is time-limited: they have editor access until Friday. System B has no concept of time-bound permissions. How should the bridge handle this when granting access in system B?",hint:"Consider what options the bridge has: grant permanent access, grant no access, or introduce a different mechanism.",solution:"The bridge cannot faithfully represent a time-limited permission in a system with no time concept. The options are: (1) Grant no access in system B until a human explicitly creates a permanent permission — most restrictive and most faithful to intent. (2) Grant access but implement time-bounding in the bridge itself, checking the expiry on every call and rejecting after the deadline — most accurate but requires the bridge to maintain state. (3) Grant permanent access and trust that the system A permission will be revoked at expiry — least secure, because the system B permission persists even after the system A permission expires. Option 2 is the right design choice for a serious production bridge."},{id:"ex9-11-3",difficulty:"advanced",question:"An agent operates across three systems with different permission models. Design a minimal permission bridge architecture that ensures no accidental privilege escalation, is auditable, and handles the case where one system's permission model changes.",hint:"Think about where the mapping is stored, who can change it, and what happens to in-flight permissions when the mapping changes.",solution:"Architecture: (1) Centralized mapping store: explicit permission maps for each system pair, stored in a version-controlled configuration that requires review and approval to change. (2) Conservative defaults: any unmapped permission is denied, not granted. Gaps must be explicitly filled by a human. (3) Audit log: every permission bridge decision (permission X in system A → permission Y in system B, for request Z) is logged with a timestamp, the mapping version used, and the outcome. (4) Versioned mappings: the mapping in effect at the time of an action is recorded in the audit log, so retrospective review is possible. When system models change, the mapping must be reviewed and updated before the agent is permitted to bridge to the changed system — a change to any participant's permission model triggers a mapping review gate. This prevents silent privilege changes from slipping through."}]})]})}const W=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));function b(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Protocol Versioning and Evolution"}),e.jsx("p",{children:"Protocols are not static. Tools evolve, capabilities are added, schemas change, and bugs are fixed. A protocol that cannot accommodate change becomes a constraint that prevents the tools that implement it from improving. Versioning is the mechanism that allows a protocol to evolve without breaking existing participants."}),e.jsx(t,{title:"Protocol Versioning",number:"9.12",children:e.jsx("p",{children:`Protocol versioning is the practice of labeling each iteration of a protocol's contract so that clients and servers can negotiate which version they will use to communicate. Versioning separates the question of "what is the latest protocol" from "what version are we actually using in this conversation," allowing new and old participants to coexist during transitions.`})}),e.jsxs("p",{children:["Changes to a protocol fall into two categories. ",e.jsx("strong",{children:"Non-breaking changes"}),"add new optional fields, new error codes, or new capabilities — existing clients can ignore what they do not understand, and the protocol remains backward compatible.",e.jsx("strong",{children:" Breaking changes"})," remove required fields, rename them, change their semantics, or remove capabilities — any client relying on the old behavior will fail. Good protocol design maximizes non-breaking evolution and gives ample notice before breaking changes take effect."]}),e.jsx(n,{title:"Be Conservative in What You Remove",number:"9.8",children:e.jsx("p",{children:"Adding to a protocol is almost always safe. Removing from a protocol breaks clients that depend on what was removed. The cost of removing a capability or field is always paid by the clients — not the server. This asymmetry means servers should be very reluctant to remove things and should provide long deprecation windows before doing so."})}),e.jsx(o,{title:"Semantic versioning for protocols",type:"note",children:e.jsx("p",{children:'Semantic versioning (major.minor.patch) maps naturally to protocol changes: patch versions for bug fixes with no schema changes, minor versions for backward-compatible additions, and major versions for breaking changes. Clients can express their compatibility range ("I support v2.0 through v2.x") and servers can advertise which versions they support, enabling clean negotiation.'})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex9-12-1",difficulty:"beginner",question:'Classify each of these protocol changes as breaking or non-breaking, and explain why: (a) adding an optional "tags" field to a response, (b) renaming "user_id" to "userId" in a request schema, (c) adding a new optional query parameter, (d) changing an error code from 404 to 422 for invalid input.',hint:"A change is breaking if any existing client that was working correctly before will fail or behave incorrectly after the change.",solution:'(a) Non-breaking: clients that do not use the new field can ignore it. (b) Breaking: any client that sends "user_id" will now be sending an unrecognized field — the request will likely fail. (c) Non-breaking: existing clients that do not send the new parameter continue to work as before. (d) Breaking: clients that check for 404 to detect invalid input will no longer trigger on 422, causing them to handle the error incorrectly. Even changes that seem minor — like error code values — are breaking if clients rely on specific values.'},{id:"ex9-12-2",difficulty:"intermediate",question:"A tool server wants to rename a required field in its response schema. It cannot break existing clients. Design a migration plan that allows old clients to keep working while new clients use the new field name.",hint:"Think about how to provide both field names simultaneously during a transition period.",solution:"A dual-field transition: (1) In the next minor version, add the new field name alongside the old one — both are present in responses. Document the old field as deprecated with a sunset date. (2) Communicate the deprecation to all known clients with the timeline. (3) After the deprecation window (long enough for all clients to update), release a new major version that removes the old field name. Clients that have updated will use the new name; clients that have not updated continue to use the old name during the window. The key principle: never remove until all clients have had reasonable opportunity to migrate, and never assume silence means they have updated."},{id:"ex9-12-3",difficulty:"advanced",question:"Design a version negotiation mechanism for an agent-tool protocol. When a client connects to a server, how should they agree on which protocol version to use? What should happen if there is no overlap between the versions each supports?",hint:"Consider negotiation patterns from existing protocols (like TLS or HTTP/2) and what information each side needs to declare.",solution:`Negotiation mechanism: (1) The client sends a capability declaration on first connection containing its supported version range (e.g., min: "2.0", max: "3.1") and any optional feature flags it supports. (2) The server responds with the highest version within the overlap range that it supports, or an explicit rejection if no overlap exists. (3) Both parties use the negotiated version for all subsequent communication in the session. If there is no overlap: the server returns a "version mismatch" error specifying the range it supports. The client can either fail gracefully (surfacing the version mismatch to a human or orchestrator) or, if it supports adapter logic, attempt to bridge the gap. The key is that the error message must be machine-readable — including the server's supported range — so the client can surface a meaningful diagnostic rather than a generic connection failure.`}]})]})}const D=Object.freeze(Object.defineProperty({__proto__:null,default:b},Symbol.toStringTag,{value:"Module"}));export{k as a,j as b,T as c,A as d,q as e,C as f,I as g,S as h,B as i,P as j,W as k,D as l,x as s};
